#!/usr/bin/env node
// Build script: embeds the MiniML stdlib sources into js/stdlib_sources.js
// for the browser playground. The self-hosted compiler (compiler_native.js)
// reads stdlib files through its readFile callback at compile time; in the
// browser those reads are served from this embedded map.
//
// (This replaces the old browser.js, which also bundled the retired JS
// bytecode VM — see roadmap #13c. The playground now has exactly one
// execution strategy: compiler_native.js compiles to JS, which runs as JS.)

const fs = require("fs");
const path = require("path");

const dir = __dirname;
const stdlibDir = path.join(dir, "..", "stdlib");

// The set of stdlib modules to embed is DERIVED from the compiler itself
// (self_host/main.mml), not hand-maintained here — a duplicated list silently
// drifts (it once dropped fs/path/process/digest, breaking the playground with
// "File not found: stdlib/fs.mml"). We scan main.mml for both ways it pulls in
// a stdlib file: the direct `"stdlib/<name>.mml"` literal (builtins, loaded
// first as the single source of builtin signatures) and every `load "<name>"`
// call (the rest, in load order). Any future `load "x"` is bundled automatically.
function stdlibFilesFromCompiler() {
  const mainMml = fs.readFileSync(
    path.join(dir, "..", "self_host", "main.mml"),
    "utf-8"
  );
  const names = [];
  const seen = new Set();
  const add = (n) => {
    if (!seen.has(n)) {
      seen.add(n);
      names.push(n);
    }
  };
  // Direct literals first (e.g. stdlib/builtins.mml, loaded specially up front).
  for (const m of mainMml.matchAll(/"stdlib\/([a-z0-9_]+)\.mml"/g)) add(m[1]);
  // Then the `load "x"` sequence, in source order.
  for (const m of mainMml.matchAll(/^\s*load\s+"([a-z0-9_]+)"/gm)) add(m[1]);
  if (names.length === 0) {
    throw new Error(
      "No stdlib modules found in self_host/main.mml — the scan patterns are stale"
    );
  }
  return names;
}

const STDLIB_FILES = stdlibFilesFromCompiler();

const stdlibSources = {};
for (const name of STDLIB_FILES) {
  stdlibSources[`stdlib/${name}.mml`] = fs.readFileSync(
    path.join(stdlibDir, `${name}.mml`),
    "utf-8"
  );
}

const bundle = `// MiniML stdlib sources - browser bundle (generated by build_stdlib_bundle.js)
(function(global) {
"use strict";

const STDLIB_SOURCES = ${JSON.stringify(stdlibSources)};

global.MiniML = Object.assign(global.MiniML || {}, {
  STDLIB_SOURCES: STDLIB_SOURCES,
});

})(typeof window !== "undefined" ? window : globalThis);
`;

const outPath = path.join(dir, "stdlib_sources.js");
fs.writeFileSync(outPath, bundle);
console.log(`Wrote ${outPath} (${(bundle.length / 1024).toFixed(1)} KB)`);
